############################################################ # PG Setup Code ############################################################ ($m, $b, $c) = random_subset(3,-9..-1,1..9); $x = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z'); Context()->variables->are($x => 'Real'); Context()->noreduce('(-x)+y', '(-x)-y'); $left = Formula("$m ($x + $b)")->reduce; $right = Formula("$m ($x + $c)")->reduce; Context("FiniteSolutionSets"); $solution = String("no real solutions")->cmp(typeMatch => Formula("{1}")); #$solution = OneOf(Compute("R"), String("infinitely many solutions"))->cmp(typeMatch => Formula("{1}"));
